const mongoose = require('mongoose');

const seatSchema = new mongoose.Schema({
    // seat_id auto-generated by Mongo DB as _id
    lab_id: {
        type: mongoose.Schema.Types.ObjectId,
        ref: "Laboratory",
        required: true
    },
    status: {
        type: String,
        enum: ["Available", "Occupied", "Closed"],
        default: "Available",
        required: true
    }
});

const Seat = new mongoose.model("Seat", seatSchema);
module.exports = Seat;